1	// Package utils provides small shared helpers for the cert-manager operator,
2	// including optional API discovery (whether a GroupVersionResource is served)
3	// and shared informer wiring that runs only when that API exists.
4	package utils
5	
6	import (
7		"fmt"
8	
9		"k8s.io/apimachinery/pkg/api/errors"
10		"k8s.io/apimachinery/pkg/runtime/schema"
11		"k8s.io/client-go/discovery"
12	)
13	
14	// ResourceDiscoverer reports whether a GroupVersionResource is served by the
15	// cluster API server (via discovery). Implementations include the value returned
16	// from NewResourceDiscoverer.
17	type ResourceDiscoverer interface {
18		Discover() (bool, error)
19	}
20	
21	// apiResourceDiscoverer implements ResourceDiscoverer using the discovery API.
22	type apiResourceDiscoverer struct {
23		gvr             schema.GroupVersionResource
24		discoveryClient discovery.DiscoveryInterface
25	}
26	
27	// OptionalInformer holds a typed informer factory only when the target API
28	// resource exists on the cluster. Populated by InitInformerIfAvailable when
29	// discovery reports the resource is served.
30	type OptionalInformer[GroupInformer any] struct {
31		InformerFactory *GroupInformer
32	}
33	
34	// NewResourceDiscoverer returns a ResourceDiscoverer for the given GVR and
35	// discovery client. Discover is not called until Discover or
36	// InitInformerIfAvailable runs.
37	func NewResourceDiscoverer(gvr schema.GroupVersionResource, discoveryClient discovery.DiscoveryInterface) ResourceDiscoverer {
38		return &apiResourceDiscoverer{
39			gvr:             gvr,
40			discoveryClient: discoveryClient,
41		}
42	}
43	
44	// Discover reports whether the API server lists a.gvr.Resource in the
45	// APIResources for the group/version in a.gvr. A NotFound error from discovery is
46	// treated as not present (false, nil); other errors are returned.
47	func (a *apiResourceDiscoverer) Discover() (bool, error) {
48		resources, err := a.discoveryClient.ServerResourcesForGroupVersion(a.gvr.GroupVersion().String())
49		if err != nil {
50			if errors.IsNotFound(err) {
51				return false, nil
52			}
53			return false, fmt.Errorf("failed to discover resources: %w", err)
54		}
55	
56		for _, res := range resources.APIResources {
57			if res.Name == a.gvr.Resource {
58				return true, nil
59			}
60		}
61	
62		return false, nil
63	}
64	
65	// InitInformerIfAvailable calls d.Discover(), and if the resource is served it
66	// calls informerInitFunc and stores the result in InformerFactory; otherwise
67	// InformerFactory remains nil and no error is returned (the API is treated as
68	// unavailable).
69	func InitInformerIfAvailable[groupInformer any](
70		d ResourceDiscoverer,
71		informerInitFunc func() groupInformer,
72	) (*OptionalInformer[groupInformer], error) {
73		o := new(OptionalInformer[groupInformer])
74	
75		discovered, err := d.Discover()
76		if err != nil {
77			return nil, err
78		}
79	
80		if discovered {
81			informer := informerInitFunc()
82			o.InformerFactory = &informer
83		}
84	
85		return o, nil
86	}
87	
88	// Applicable reports whether an informer factory was set (the API was present).
89	func (o *OptionalInformer[GroupInformer]) Applicable() bool {
90		return o.InformerFactory != nil
91	}
92

1	package trustmanager
2	
3	import (
4		"fmt"
5		"os"
6	
7		"github.com/openshift/cert-manager-operator/api/operator/v1alpha1"
8		"github.com/openshift/cert-manager-operator/pkg/controller/common"
