	&appsv1.Deployment{},
	&rbacv1.ClusterRole{},
	&rbacv1.ClusterRoleBinding{},
	&rbacv1.Role{},
	&rbacv1.RoleBinding{},
	&corev1.Service{},
	&corev1.ServiceAccount{},
	&networkingv1.NetworkPolicy{},
